import React from 'react';
import { Link } from 'react-router-dom';
import '../styles/HeaderStyles.css';


import IconButton from '@material-ui/core/IconButton';
import MapIcon from '@material-ui/icons/Map';
import RateReviewOutlinedIcon from '@material-ui/icons/RateReviewOutlined';


const Header = () => {
      return (
      <div className='nav'>
            <IconButton edge="start">
              <Link to='/posts' className='link icon'><RateReviewOutlinedIcon /></Link>
            </IconButton>
            <div className="link parkly">
              <Link to='/' className='link parkly'>Bug Trackerly</Link>              
            </div>
            <div>
                <Link>User</Link>
                <div>
                    <Link to='/bugs'>My Bugs</Link>
                    <Link to='/user:id'>Account</Link>
                    <Link to='/signIn'>Auth</Link>
                </div>
            </div>
      </div>
    );
  }




export default Header;
